		&lt;li&gt;From Goa to Kanyakumari &amp;ndash;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Malabar Coast&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;strong&gt;कोरोमंडल तट&lt;/strong&gt;&lt;/u&gt; &lt;span style=&quot;&quot;&gt;है&lt;/span&gt;।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;कोपेन के वर्गीकरण के अनुसार कोरोमंडल तट की जलवायु &amp;#39;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;As&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;#39; प्रकार की&lt;/span&gt; &lt;span style=&quot;&quot;&gt;है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कोरोमंडल तट&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;यह पूर्वी &lt;span style=&quot;font-weight: 700;&quot;&gt;तमिलनाडु राज्य&lt;/span&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;में तटीय मैदान है&lt;/span&gt;।&lt;/li&gt;
		&lt;li&gt;यह उत्तर में &lt;span style=&quot;font-weight: 700;&quot;&gt;उत्कल मैदान, पूर्व में बंगाल की खाड़ी, दक्षिण में कावेरी डेल्टा&lt;/span&gt; और &lt;span style=&quot;font-weight: 700;&quot;&gt;पश्चिम में पूर्वी घाट से घिरा है।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;लगभग &lt;span style=&quot;font-weight: 700;&quot;&gt;22,800 वर्ग किलोमीटर के क्षेत्र में फैला हुआ है।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt; &lt;span style=&quot;font-weight: 700; &quot;&gt;कोपेन के वर्गीकरण के अनुसार कोरोमंडल तट की जलवायु &amp;#39;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;As&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;#39; प्रकार की है।&lt;/span&gt;&lt;/li&gt;
